  ('elementary-acfc4025-moex-00829', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '我國憲法第23條規定：「以上各條列舉之自由權利，除為防止妨害他人自由、避免緊急危難、維持社會', '["比例原則", "法律保留原則", "誠實信用原則", "信賴保護原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00830', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '1989 年國小老師李幸長發起「無殼蝸牛運動」，夜宿臺北市忠孝東路，抗議政府漠視人民的居住權益。 後來，無住屋運動轉型為「崔媽媽基金會」，透過協助弱勢族群解決租屋問題，落實「居者適其屋」的 理念。關於「無殼蝸牛運動」發展到「崔媽媽基金會」之成立，下列敘述何者正確？', '["由非營利組織轉型為營利組織", "原強調利他主義後轉為主張利己導向", "原以公益為使命後轉為重視成本效益", "從倡議的社會運動轉為成立服務性的社團"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL)
